func (a *adapter) GetAddonFoo(ctx context.Context, params addon.GetFooInput) (*addon.Foo, error) {
	fn := func(ctx context.Context, a *adapter) (*addon.Foo, error) {
		if err := params.Validate(); err != nil { return nil, fmt.Errorf("invalid params: %w", err) }
		row, err := a.db.AddonFoo.Query().Where(...).WithRatecards(AddonEagerLoadRateCardsFn).First(ctx)
		if err != nil { if entdb.IsNotFound(err) { return nil, addon.NewNotFoundError(...) }; return nil, err }
		return FromAddonFooRow(*row)
	}
	return entutils.TransactingRepo[*addon.Foo, *adapter](ctx, a, fn)
}

type ( CloneAddonRequest = addon.CloneAddonInput; CloneAddonResponse = api.Addon; CloneAddonHandler httptransport.HandlerWithArgs[CloneAddonRequest, CloneAddonResponse, string] )

func (h *handler) CloneAddon() CloneAddonHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, addonID string) (CloneAddonRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return CloneAddonRequest{}, err }
			return CloneAddonRequest{NamespacedID: models.NamespacedID{Namespace: ns, ID: addonID}}, nil
		},
		func(ctx context.Context, request CloneAddonRequest) (CloneAddonResponse, error) { a, err := h.service.CloneAddon(ctx, request); ... },
	)
}

func (s service) CloneAddon(ctx context.Context, params addon.CloneAddonInput) (*addon.Addon, error) {
	fn := func(ctx context.Context) (*addon.Addon, error) {
		if err := params.Validate(); err != nil { return nil, fmt.Errorf("invalid clone params: %w", err) }
		if err = s.resolveFeatures(ctx, params.Namespace, &newRateCards); err != nil { return nil, err }
		if err = s.resolveTaxCodes(ctx, params.Namespace, &newRateCards); err != nil { return nil, err }
		cloned, err := s.adapter.CreateAddon(ctx, createInput)
		if err != nil { return nil, err }
		if err = s.publisher.Publish(ctx, addon.NewAddonCreateEvent(ctx, cloned)); err != nil { return nil, err }
		return cloned, nil
	}
	return transaction.Run(ctx, s.adapter, fn)
}
